export type Cell = [number, number];

const keyOf = ([x, y]: Cell): string => `${x},${y}`;

const survives = (isAlive: boolean, neighbors: number): boolean =>
  (isAlive && (neighbors === 2 || neighbors === 3)) ||
  (!isAlive && neighbors === 3);

export const nextGeneration = (liveCells: Cell[]): Cell[] => {
  const liveKeys = new Set(liveCells.map(keyOf));
  const neighborCounts = new Map<string, { cell: Cell; count: number }>();

  for (const [x, y] of liveCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const neighbor: Cell = [x + dx, y + dy];
        const k = keyOf(neighbor);
        const existing = neighborCounts.get(k);
        if (existing) existing.count++;
        else neighborCounts.set(k, { cell: neighbor, count: 1 });
      }
    }
  }

  const result: Cell[] = [];
  for (const [k, { cell, count }] of neighborCounts) {
    if (survives(liveKeys.has(k), count)) result.push(cell);
  }

  return result;
};

export type Cell = [number, number];

const keyOf = ([x, y]: Cell): string => `${x},${y}`;

const survives = (isAlive: boolean, neighbors: number): boolean =>
  (isAlive && (neighbors === 2 || neighbors === 3)) ||
  (!isAlive && neighbors === 3);

const neighborsOf = ([x, y]: Cell): Cell[] => {
  const result: Cell[] = [];
  for (let dx = -1; dx <= 1; dx++) {
    for (let dy = -1; dy <= 1; dy++) {
      if (dx !== 0 || dy !== 0) result.push([x + dx, y + dy]);
    }
  }
  return result;
};

export const nextGeneration = (liveCells: Cell[]): Cell[] => {
  const liveKeys = new Set(liveCells.map(keyOf));
  const cellsByKey = new Map<string, Cell>();
  const neighborCounts = new Map<string, number>();

  for (const cell of liveCells) {
    for (const neighbor of neighborsOf(cell)) {
      const k = keyOf(neighbor);
      cellsByKey.set(k, neighbor);
      neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
    }
  }

  const result: Cell[] = [];
  for (const [k, count] of neighborCounts) {
    if (survives(liveKeys.has(k), count)) result.push(cellsByKey.get(k)!);
  }

  return result;
};
